public class JSONFunctions {
    public static Slice jsonExtract(Slice json, JSONPath path) {
        byte[] bytes = json.byteArray();
        int off = json.byteArrayOffset();
        int length = json.length();
        JSONReader jsonReader = JSONReader.of(bytes, off, length);
        SliceValueConsumer sliceValueConsumer = new SliceValueConsumer();
        path.extract(jsonReader, sliceValueConsumer);
        return sliceValueConsumer.slice;
    }
}

public interface NameFilter
        extends SerializeFilter, com.alibaba.fastjson2.filter.NameFilter {
    static NameFilter of(PropertyNamingStrategy namingStrategy) {
        return (object, name, value) -> BeanUtils.fieldName(name, namingStrategy.name());
    }

    static NameFilter compose(NameFilter before, NameFilter after) {
        return (object, name, value) ->
                after.process(
                        object,
                        before.process(object, name, value),
                        value
                );
    }
}
